#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M, N, K;
        scanf("%d %d %d", &M, &N, &K);
        int** elevation = (int**)malloc(M * sizeof(int*));
        for (int i = 0; i < M; i++) {
            elevation[i] = (int*)malloc(N * sizeof(int));
            for (int j = 0; j < N; j++) {
                scanf("%d", &elevation[i][j]);
            }
        }
        printf("Case %d:\n", T - T + 1);
        for (int i = 0; i <= M - K; i++) {
            for (int j = 0; j <= N - K; j++) {
                int maxElevation = -1;
                int count = 0;
                for (int x = i; x < i + K; x++) {
                    for (int y = j; y < j + K; y++) {
                        if (elevation[x][y] > maxElevation) {
                            maxElevation = elevation[x][y];
                            count = 1;
                        } else if (elevation[x][y] == maxElevation) {
                            count++;
                        }
                    }
                }
                printf("%d", maxElevation);
                if (count > 1) {
                    printf("(%d)", count);
                }
                if (j < N - K) {
                    printf(" ");
                }
            }
            printf("\n");
        }
        for (int i = 0; i < M; i++) {
            free(elevation[i]);
        }
        free(elevation);
    }
    return 0;
}

