import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int M = scanner.nextInt();
            int N = scanner.nextInt();
            int K = scanner.nextInt();
            int[][] elevation = new int[M][N];
            for (int i = 0; i < M; i++) {
                for (int j = 0; j < N; j++) {
                    elevation[i][j] = scanner.nextInt();
                }
            }
            System.out.println("Case " + (T + 1) + ":");
            for (int i = 0; i <= M - K; i++) {
                for (int j = 0; j <= N - K; j++) {
                    int maxElevation = -1;
                    int count = 0;
                    for (int x = i; x < i + K; x++) {
                        for (int y = j; y < j + K; y++) {
                            if (elevation[x][y] > maxElevation) {
                                maxElevation = elevation[x][y];
                                count = 1;
                            } else if (elevation[x][y] == maxElevation) {
                                count++;
                            }
                        }
                    }
                    System.out.print(maxElevation);
                    if (count > 1) {
                        System.out.print("(" + count + ")");
                    }
                    if (j < N - K) {
                        System.out.print(" ");
                    }
                }
                System.out.println();
            }
        }
    }
}

